import React, { useState } from 'react';


export default function GameBord() {
const [dec, setDec] = useState({})
const [playerDec, setPlayerDec] = useState({})
const [computerDec, setComputerDec] = useState({})
const totalCards= 52
const copyFromEatchCard = 4

let createDec= ()=>{
    let mainDec=[]
    for(let i=1;i<= totalCards/2;i++){
        for(let x=1; x<=copyFromEatchCard;x++){
            mainDec.push(x)

        }
    }
    setDec(mainDec)
    giveCards()
}
let giveCards= ()=>{
    let pDec=[]
    let cDec=[]
    let decHolder = dec
    while (decHolder.length>0){
        pDec.push(decHolder.splice(Math.floor(Math.random() * decHolder.length)))
        cDec.push(decHolder.splice(Math.floor(Math.random() * decHolder.length)))
    }
    setPlayerDec(pDec)
    setComputerDec(cDec)
    console.log(playerDec)
    console.log(computerDec)

}




  return (
    <div>
        <button onClick={()=>createDec}></button>
<h1>hettt</h1>
    </div>
  )
}
